import{_ as r,o as t,c as i,ag as a}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"Architectural Decision Records (ADR) — adr.github.io overview","description":"Notes on Architectural Decision Records (ADR) — adr.github.io overview.","frontmatter":{"title":"Architectural Decision Records (ADR) — adr.github.io overview","description":"Notes on Architectural Decision Records (ADR) — adr.github.io overview."},"headers":[],"relativePath":"software-engineering/principles-and-practices/adr.github.io-architectural-decision-records-overview.md","filePath":"software-engineering/principles-and-practices/adr.github.io-architectural-decision-records-overview.md"}'),n={name:"software-engineering/principles-and-practices/adr.github.io-architectural-decision-records-overview.md"};function o(s,e,c,l,h,d){return t(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="architectural-decision-records-adr-—-adr-github-io-overview" tabindex="-1">Architectural Decision Records (ADR) — adr.github.io overview <a class="header-anchor" href="#architectural-decision-records-adr-—-adr-github-io-overview" aria-label="Permalink to &quot;Architectural Decision Records (ADR) — adr.github.io overview&quot;">​</a></h1><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li>Type: webpage</li><li>Origin: <a href="https://adr.github.io/" target="_blank" rel="noreferrer">https://adr.github.io/</a></li><li>Imported: 2026-05-24</li><li>Images: The page body is textual (definitions, lists, external links only). No inline diagrams or screenshots appeared in HTML and there was no <code>og:image</code>; nothing substantive to embed beyond optional site chrome, so none were bundled into <code>assets/</code>.</li></ul><h2 id="content" tabindex="-1">Content <a class="header-anchor" href="#content" aria-label="Permalink to &quot;Content&quot;">​</a></h2><h3 id="motivation-and-definitions" tabindex="-1">Motivation and definitions <a class="header-anchor" href="#motivation-and-definitions" aria-label="Permalink to &quot;Motivation and definitions&quot;">​</a></h3><p>An <a href="https://en.wikipedia.org/wiki/Architectural_decision" target="_blank" rel="noreferrer">Architectural Decision (AD)</a> is a justified design choice that addresses a functional or non-functional requirement that is architecturally significant. An <a href="https://en.wikipedia.org/wiki/Architecturally_significant_requirements" target="_blank" rel="noreferrer">Architecturally Significant Requirement (ASR)</a> is a requirement that has a measurable effect on the architecture and quality of a software and/or hardware system. An Architectural Decision Record (ADR) captures a single AD and its rationale. In short, an ADR surfaces the reasons for a chosen architectural decision, along with trade-offs and consequences.</p><p>The collection of ADRs maintained in a project is its decision log. This sits within Architectural Knowledge Management (AKM), though ADR practice can extend to design and other decisions (“any decision record”).</p><p>The aim of the <a href="https://github.com/adr" target="_blank" rel="noreferrer">GitHub <code>adr</code> organization</a> is to:</p><ol><li>Motivate the need for capturing decisions and establish a shared vocabulary.</li><li>Strengthen ADR tooling in support of agile and iterative/incremental engineering.</li><li>Point to public knowledge related to AKM and ADRs.</li></ol><h3 id="adrs-in-the-media" tabindex="-1">ADRs in the media <a class="header-anchor" href="#adrs-in-the-media" aria-label="Permalink to &quot;ADRs in the media&quot;">​</a></h3><ul><li><em>(German)</em> Slides <em><a href="https://adr.github.io/assets/2026-03-10%20-%20ADR%2C%20MADR%2C%20eADR%20-%20JavaLand%202026.pdf" target="_blank" rel="noreferrer">Architekturentscheidungen sichtbar und nachvollziehbar gestalten</a></em> at <a href="https://www.javaland.eu/" target="_blank" rel="noreferrer">JavaLand 2026</a>, 2026-03-10.</li><li><a href="https://learn.microsoft.com/en-us/azure/well-architected/architect-role/architecture-decision-record" target="_blank" rel="noreferrer">Azure Well-Architected Framework</a> features ADRs and links this site (2024-11-10).</li><li><a href="https://ieeexplore.ieee.org/document/9801811" target="_blank" rel="noreferrer">Love Unrequited: The Story of Architecture, Agile, and How Architecture Decision Records Brought Them Together</a>, Michael Keeling, <em>IEEE Software</em> Vol. 39 Issue 4 (2022) (<a href="https://ieeexplore.ieee.org/stamp/stamp.jsp?arnumber=9801811" target="_blank" rel="noreferrer">PDF stamp</a>).</li><li><a href="https://leanpub.com/dpr" target="_blank" rel="noreferrer">Design Practice Reference</a> (LeanPub) positions capturing architectural decisions as essential.</li><li>Chapter 3 of <a href="https://api-patterns.org/book/" target="_blank" rel="noreferrer">“Patterns for API Design…”</a> discusses recurring API design decisions with options and criteria (<a href="https://medium.com/nerd-for-tech/api-patterns-website-redesigned-and-sample-book-chapter-available-df9daf4b5e15" target="_blank" rel="noreferrer">related blog post</a>).</li><li><em>(German)</em> <a href="https://www.heise.de/hintergrund/Gut-dokumentiert-Architecture-Decision-Records-4664988.html" target="_blank" rel="noreferrer">Gut dokumentiert: Architecture Decision Records</a> by <a href="https://github.com/obfischer" target="_blank" rel="noreferrer">@obfischer</a>, heise online.</li></ul><h3 id="background-information" tabindex="-1">Background information <a class="header-anchor" href="#background-information" aria-label="Permalink to &quot;Background information&quot;">​</a></h3><p>Organization work aligns with <em><a href="https://www.infoq.com/articles/sustainable-architectural-design-decisions" target="_blank" rel="noreferrer">Sustainable Architectural Decisions</a></em> (Zdun et al.), including the Y-statement format from that piece.</p><p>Further pointers mentioned on the site:</p><ul><li><em><a href="https://www.ost.ch/fileadmin/dateiliste/3_forschung_dienstleistung/institute/ifs/cloud-application-lab/admentor-wicsa2015ubmissionv11nc.pdf" target="_blank" rel="noreferrer">Architectural Decision Guidance Across Projects …</a></em> (WICSA 2015) — comparison of seven templates.</li><li><a href="https://www.ozimmer.ch/practices/2020/04/27/ArchitectureDecisionMaking.html" target="_blank" rel="noreferrer">Architectural Decisions — The Making Of</a> — history since the late 1990s, examples, rationale guidance.</li><li><a href="https://cognitect.com/blog/2011/11/15/documenting-architecture-decisions.html" target="_blank" rel="noreferrer">Documenting Architecture Decisions</a> — Michael Nygard (2011), cited as popularizing the idea.</li><li><a href="https://openpracticelibrary.com/practice/architectural-decision-records-adr/" target="_blank" rel="noreferrer">Architectural Decision Records (ADR)</a> in the Open Practice Library.</li><li>AWS: <a href="https://docs.aws.amazon.com/prescriptive-guidance/latest/architectural-decision-records/welcome.html" target="_blank" rel="noreferrer">Architectural decision records</a>.</li><li>Video: <a href="https://www.youtube.com/watch?v=41NVge3_cYo" target="_blank" rel="noreferrer">Architecture Decision Records in Action</a> (Michael Keeling, Joe Runde).</li><li>Series: <a href="https://www.developertoarchitect.com/lessons/lesson168.html" target="_blank" rel="noreferrer">ADRs and Architecture Stories</a> (Mark Richards).</li><li><a href="https://www.ost.ch/en/research-and-consulting-services/computer-science/ifs-institute-for-software-new/cloud-application-lab/architectural-knowledge-management-akm" target="_blank" rel="noreferrer">Architectural Knowledge Management (AKM)</a> landing page.</li></ul><h3 id="related-sections-on-the-same-site" tabindex="-1">Related sections on the same site <a class="header-anchor" href="#related-sections-on-the-same-site" aria-label="Permalink to &quot;Related sections on the same site&quot;">​</a></h3><ul><li><a href="https://adr.github.io/ad-practices/" target="_blank" rel="noreferrer">ADR practices</a></li><li><a href="https://adr.github.io/adr-templates/" target="_blank" rel="noreferrer">ADR templates</a></li><li><a href="https://adr.github.io/adr-tooling/" target="_blank" rel="noreferrer">Decision capturing tools</a></li></ul><h2 id="key-takeaways" tabindex="-1">Key takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key takeaways&quot;">​</a></h2><ul><li><strong>ADR</strong>: one structured record per significant decision, with rationale and consequences; collectively they form the project decision log under the broader umbrella of Architectural Knowledge Management.</li><li><strong><code>adr</code> on GitHub</strong> exists to evangelize terminology, tooling, and links to authoritative reading (Nygard, Zdun et al., industry guides, practitioner media).</li><li>The homepage is primarily a curated index — deep structure lives in sub-pages (practices, templates, tooling).</li></ul>',19)])])}const p=r(n,[["render",o]]);export{g as __pageData,p as default};
